import React, { useEffect, useState } from 'react'
import styled from 'styled-components'


const DesignerIntroWrapper = styled.div `
width:80%;
height:500px;
border:1px solid rgb(180, 180, 180);
margin:60px auto;
border-radius:3px;
overflow:hidden;
box-sizing:border-box;
position:relative;
`

const Banner = styled.div `
height:40%;
background-image:url('https://i.ytimg.com/vi/F_24Zwi9jBA/maxresdefault.jpg');
background-size:cover;
background-position:center;
`

const Body = styled.div `
height:60%;
margin-top:30px;
padding:0 18%;
line-height:30px;
font-size:1rem;
`

const HideSection = styled.div `
position:absolute;
margin-top:400px;
height:100px;
background:linear-gradient(to top, white, transparent);
width:100%;
display:flex;
padding:20px 40px;
box-sizing:border-box;
justify-content:flex-end;
align-items:flex-end;

`

const ReadMore =styled.div `
width:100px;
height:30px;
background-color:white;
font-size:0.7rem;
font-weight:800;
color:rgb(70, 70, 70);
border-radius:5px;
line-height:30px;
text-align:center;
border:1px solid rgb(70, 70, 70);
&:hover {
	cursor:pointer;
}
`

const BrandAvatar = styled.div `
height:140px;
width:140px;
margin-top:40%;
margin-left:10%;
border-radius:50%;
position:absolute;
background-image:url('https://i0.wp.com/andjoy.store/wp-content/uploads/2019/09/Maison-Margiela.png?fit=870%2C435&ssl=1');
background-size:cover;
background-position:center;
border:0;
`

export default function DesignerIntroSection () {



	return (
		<DesignerIntroWrapper>
			<BrandAvatar/>
			<HideSection>
				<ReadMore>READ MORE</ReadMore>
			</HideSection>
			<Banner></Banner>
			<Body>
				Maison Margiela, formerly Maison Martin Margiela, is a French luxury fashion house founded by Martin Margiela and Jenny Meirens[1] in 1988 and headquartered in Paris.[2] The house produces both haute couture-inspired artisanal collections and ready-to-wear collections, with the former influencing the designs of the latter.[3] Product lines include womenswear, menswear, fine jewelry, footwear, objects, fragrance,[2] and home goods, among others.[4] Known for deconstructive and avant-garde designs with unconventional materials,[2] Maison Margiela has traditionally held live shows in unusual settings, for example empty metro stations[5] and street corners.[6] Models' faces are often obscured[7] by fabric or long hair to direct attention to the clothes and design.[8] Margiela resigned as creative designer in 2009[9] and John Galliano was appointed to the role in 2014.
			</Body>
		</DesignerIntroWrapper>
	)
}
